    it('should handle ConfigMap websocket messages via the listener', async () => {
      await store.dispatch(actionCreators.subscribeToConfigMapChanges());

      const listener = mockAddChannelMessageListener.mock.calls[0][1] as ChannelListener;

      const configMapMessage: api.webSocket.ConfigMapMessage = {
        eventPhase: api.webSocket.EventPhase.MODIFIED,
        configMap: {
          metadata: { resourceVersion: '999' },
          data: {
            'devfile-a': 'schemaVersion: 2.2.2\nmetadata:\n  name: test-a',
          },
        },
      };

      listener(configMapMessage);

      const actions = store.getActions();
      const configMapVersionAction = actions.find(
        (a: { type: string }) => a.type === 'localDevfiles/setConfigMapResourceVersion',
      );
      expect(configMapVersionAction).toBeDefined();
      expect(configMapVersionAction.payload).toBe('999');

      const successAction = actions.find(
        (a: { type: string }) => a.type === 'localDevfiles/requestSuccess',
      );
      expect(successAction).toBeDefined();
      expect(successAction.payload).toHaveLength(1);
      expect(successAction.payload[0].id).toBe('devfile-a');
      expect(successAction.payload[0].name).toBe('test-a');
    });

